const InteractiveTerminal = () => {
  const [logs, setLogs] = useState<string[]>([
    "ABRAHAM_OS [Version 2.4.9]",
    "(c) 2025 Abraham Baraka Systems. All rights reserved.",
    "",
    "Establishing encrypted connection via Node-421...",
    "Status: SECURE - Proxy active.",
    "Type 'help' to see available commands."
  ]);
  const [input, setInput] = useState("");
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [logs]);

  const handleCommand = (e: React.FormEvent) => {
    e.preventDefault();
    const cmd = input.trim().toLowerCase();
    if (!cmd) return;

    let response = [`> ${input}`];

    switch(cmd) {
      case 'help':
        response.push("Available commands: about, work, skills, contact, clear, hack, system");
        break;
      case 'about':
        response.push("Abraham Baraka: Software Architect & Security Expert. Specializing in secure data and cinematic UX.");
        break;
      case 'skills':
        response.push("Expertise sectors: CREATIVITY, CORE_ENG, CYBER_DEFENSE.");
        break;
      case 'work':
        response.push("Projects available: Vortex Secure, Omni Vision, Hades Protocol, Zenith Platform.");
        break;
      case 'hack':
        response.push("Executing brute-force simulation...");
        response.push("[####..........] 20%");
        setTimeout(() => {
           setLogs(prev => [...prev, "[########......] 60%", "[############..] 90%", "[SUCCESS] Access Point Compromised."]);
        }, 1000);
        break;
      case 'system':
        response.push("CPU: Quantum-Core i9 | RAM: 512GB Virtual | Network: Encrypted Fiber");
        break;
      case 'clear':
        setLogs([]);
        setInput("");
        return;
      default:
        response.push(`Command not found: ${cmd}. Type 'help' for instructions.`);
    }

    setLogs(prev => [...prev, ...response]);
    setInput("");
  };

  return (
    <section id="terminal" className="py-32 px-6 relative bg-slate-950">
      <div className="absolute top-0 left-0 w-full h-full opacity-[0.03] pointer-events-none">
        <div className="absolute inset-0" style={{ backgroundImage: 'radial-gradient(#22d3ee 1.5px, transparent 1.5px)', backgroundSize: '60px 60px' }}></div>
