        <div className="mb-16">
          <div className="flex items-center gap-4 mb-4">
             <div className="h-[1px] w-12 bg-cyan-500"></div>
             <span className="text-cyan-400 mono text-sm tracking-[0.4em] uppercase">Phase 03</span>
          </div>
          <h2 className="text-5xl md:text-6xl font-black uppercase tracking-tighter leading-none">Security<br/>Interface</h2>
        </div>

        <motion.div 
          initial={{ opacity: 0, scale: 0.98 }}
          whileInView={{ opacity: 1, scale: 1 }}
          viewport={{ once: true }}
          className="bg-black/90 border border-white/10 rounded-sm shadow-[0_30px_100px_rgba(0,0,0,0.8)] overflow-hidden"
        >
          {/* Top Bar */}
          <div className="bg-[#111] px-5 py-3 border-b border-white/5 flex justify-between items-center">
            <div className="flex gap-2.5">
              <div className="w-3 h-3 rounded-full bg-red-500/30"></div>
              <div className="w-3 h-3 rounded-full bg-yellow-500/30"></div>
              <div className="w-3 h-3 rounded-full bg-emerald-500/30"></div>
            </div>
            <div className="text-[10px] mono text-slate-500 uppercase tracking-widest flex items-center gap-2">
