            className="p-8 h-[450px] overflow-y-auto mono text-sm md:text-base scrollbar-hide bg-[url('https://grainy-gradients.vercel.app/noise.svg')] bg-repeat opacity-90"
          >
            <div className="space-y-1.5">
              {logs.map((log, i) => (
                <div 
                  key={i} 
                  className={`${log.startsWith('>') ? 'text-white font-bold' : log.includes('[SUCCESS]') || log.includes('operational') ? 'text-emerald-400' : log.includes('[WARN]') || log.includes('not found') ? 'text-red-400' : 'text-cyan-400/90'}`}
                >
                  {log}
                </div>
              ))}
              <form onSubmit={handleCommand} className="flex items-center gap-3 text-white mt-4">
                <span className="text-emerald-500 font-bold">root@abraham:~$</span>
                <input 
                  type="text" 
