const TerminalView = () => {
  const [logs, setLogs] = useState<string[]>([
    "Abraham_OS [Version 10.0.19045.3803]",
    "(c) Abraham Baraka Systems. All rights reserved.",
    "",
    "Establishing encrypted connection via NODE-PARIS...",
    "Status: SECURE - Proxy active.",
    "Type 'help' for available commands."
  ]);
  const [input, setInput] = useState("");
  const consoleRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (consoleRef.current) {
      consoleRef.current.scrollTop = consoleRef.current.scrollHeight;
    }
  }, [logs]);

  const handleCmd = (e: React.FormEvent) => {
    e.preventDefault();
    const cmd = input.trim().toLowerCase();
    if (!cmd) return;

    let response = [`> ${input}`];
    switch(cmd) {
      case 'help': response.push("Commands: about, skills, contact, clear, whoami, system"); break;
      case 'about': response.push("Abraham Baraka: A multidisciplinary engineer merging security and aesthetics."); break;
      case 'skills': response.push("Expertise: React, Rust, Ethical Hacking, UI/UX Design."); break;
      case 'whoami': response.push("guest_user_421 (Read-only access granted)"); break;
      case 'system': response.push("CPU: Quantum-Core i9 | RAM: 512GB Virtual | Network: Encrypted Fiber"); break;
      case 'clear': setLogs([]); setInput(""); return;
      default: response.push(`Command not found: ${cmd}. Type 'help' for instructions.`);
    }

    setLogs(prev => [...prev, ...response]);
    setInput("");
  };

  return (
    <motion.section {...pageVariants} className="pt-32 pb-24 px-6 flex flex-col items-center justify-center min-h-[80vh]">
