              <TerminalIcon size={12} className="text-cyan-400" /> secure_session@abraham
            </div>
          </div>
          <div ref={consoleRef} className="p-8 h-[500px] overflow-y-auto mono text-sm md:text-base bg-[url('https://grainy-gradients.vercel.app/noise.svg')] bg-repeat opacity-90">
             <div className="space-y-1.5">
               {logs.map((log, i) => (
                 <div key={i} className={`${log.startsWith('>') ? 'text-white' : 'text-cyan-500/80'}`}>{log}</div>
