             <span className="text-cyan-400 mono text-sm tracking-[0.5em] uppercase">Phase_03</span>
          </div>
          <h2 className="text-6xl md:text-8xl font-black uppercase tracking-tighter leading-none mb-10">SYSTEM<br/>TERMINAL</h2>
        </div>

        <div className="bg-black/80 border border-cyan-500/20 rounded-xl shadow-[0_30px_100px_rgba(0,0,0,0.8)] overflow-hidden">
          <div className="bg-[#111] px-6 py-3 border-b border-white/5 flex justify-between items-center">
            <div className="flex gap-2.5">
              <div className="w-3.5 h-3.5 rounded-full bg-red-500/30"></div>
              <div className="w-3.5 h-3.5 rounded-full bg-yellow-500/30"></div>
              <div className="w-3.5 h-3.5 rounded-full bg-emerald-500/30"></div>
            </div>
            <div className="text-[10px] mono text-slate-500 uppercase tracking-widest flex items-center gap-2">
               <TerminalIcon size={14} className="text-cyan-400" /> secure_session@abaraka-vault
            </div>
            <div className="text-[10px] mono text-slate-700 hidden md:block">SSH PORT: 2288</div>
          </div>

          <div ref={scrollRef} className="p-10 h-[500px] overflow-y-auto mono text-sm md:text-base leading-relaxed bg-[url('https://grainy-gradients.vercel.app/noise.svg')] bg-repeat opacity-90">
             <div className="space-y-2">
               {logs.map((log, i) => (
                 <div key={i} className={`${log.startsWith('>') ? 'text-white font-bold' : log.includes('SUCCESS') ? 'text-emerald-400' : 'text-cyan-400/80'}`}>
                   {log}
                 </div>
               ))}
               <form onSubmit={handleCommand} className="flex items-center gap-3 text-white mt-6">
                 <span className="text-emerald-500 font-bold">root@abraham:~$</span>
